// import React, { useState } from "react";

export default function Hero({ data }) {
  const { name, title, subtitle, tagline, contact, stats } = data;
  const [menuOpen, setMenuOpen] = useState(false);

  return (
    <>
      <style>{`
        /* ── RESET ── */
        *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }

        /* ── TOKENS ── */
        :root {
          --cyan:    #00e5ff;
          --purple:  #7c3aed;
          --orange:  #f97316;
          --bg:      #0a0a0f;
          --surface: #111118;
          --surface2:#16161f;
          --border:  rgba(255,255,255,0.08);
          --text:    #e8e8f0;
          --muted:   #7777a0;
          --nav-h:   64px;
          --max:     860px;
          --pad:     clamp(1.25rem, 5vw, 4rem);
        }

        /* ── NAV ── */
        .ac-nav {
          position: fixed; top: 0; left: 0; right: 0;
          height: var(--nav-h);
          display: flex; align-items: center; justify-content: space-between;
          padding: 0 var(--pad);
          background: rgba(10,10,15,0.9);
          backdrop-filter: blur(14px);
          border-bottom: 1px solid var(--border);
          z-index: 100;
        }
        .ac-logo { display: flex; align-items: center; gap: 6px; font-weight: 800; font-size: 1.15rem; letter-spacing: -0.02em; }
        .ac-logo-ac  { color: var(--cyan); }
        .ac-logo-dev { color: var(--muted); font-size: 0.78rem; font-weight: 500; }

        .ac-nav-links { display: flex; align-items: center; gap: clamp(14px,2vw,28px); list-style: none; }
        .ac-nav-links a { color: var(--muted); text-decoration: none; font-size: 0.85rem; transition: color .2s; }
        .ac-nav-links a:hover { color: var(--text); }

        .ac-btn-hire {
          background: var(--cyan); color: #000; border: none;
          padding: 8px 18px; border-radius: 50px;
          font-weight: 700; font-size: 0.82rem; cursor: pointer;
          text-decoration: none; white-space: nowrap; display: inline-block;
          transition: opacity .2s;
        }
        .ac-btn-hire:hover { opacity: .85; }

        .ac-hamburger {
          display: none; flex-direction: column; gap: 5px;
          cursor: pointer; background: none; border: none; padding: 4px;
        }
        .ac-hamburger span {
          display: block; width: 22px; height: 2px;
          background: var(--text); border-radius: 2px;
        }

        /* ── MOBILE MENU ── */
        .ac-mobile-menu {
          display: none; position: fixed;
          top: var(--nav-h); left: 0; right: 0;
          background: rgba(10,10,15,0.97);
          border-bottom: 1px solid var(--border);
          padding: 20px var(--pad);
          z-index: 99; flex-direction: column; gap: 18px;
        }
        .ac-mobile-menu.open { display: flex; }
        .ac-mobile-menu a { color: var(--text); text-decoration: none; font-size: 1rem; font-weight: 500; }

        /* ── HERO ── */
        .ac-hero {
          min-height: 100vh;
          display: flex; flex-direction: column; justify-content: center;
          padding: calc(var(--nav-h) + clamp(2rem,6vw,5rem)) var(--pad) clamp(2.5rem,5vw,4rem);
          position: relative; overflow: hidden;
          background: var(--bg);
        }
        .ac-blob1 {
          position: absolute; top: -8%; right: -4%;
          width: clamp(180px,35vw,460px); height: clamp(180px,35vw,460px);
          border-radius: 50%;
          background: radial-gradient(circle, rgba(124,58,237,0.14) 0%, transparent 70%);
          pointer-events: none;
        }
        .ac-blob2 {
          position: absolute; bottom: -5%; left: -8%;
          width: clamp(140px,28vw,340px); height: clamp(140px,28vw,340px);
          border-radius: 50%;
          background: radial-gradient(circle, rgba(0,229,255,0.08) 0%, transparent 70%);
          pointer-events: none;
        }
        .ac-hero-inner { max-width: var(--max); width: 100%; position: relative; z-index: 1; }

        /* ── BADGE ── */
        .ac-badge {
          display: inline-flex; align-items: center; gap: 8px;
          background: rgba(0,229,255,0.08);
          border: 1px solid rgba(0,229,255,0.2);
          border-radius: 99px; padding: 5px 14px;
          margin-bottom: clamp(1rem,2.5vw,1.5rem);
        }
        .ac-badge-dot {
          width: 7px; height: 7px; border-radius: 50%;
          background: var(--cyan); flex-shrink: 0;
          animation: ac-pulse 2s infinite;
        }
        @keyframes ac-pulse {
          0%,100% { opacity:1; transform:scale(1); }
          50%      { opacity:.6; transform:scale(0.85); }
        }
        .ac-badge-txt {
          font-size: 0.67rem; color: var(--cyan); font-weight: 700;
          letter-spacing: .07em; text-transform: uppercase; white-space: nowrap;
        }

        /* ── NAME ── */
        .ac-hero-name {
          font-weight: 800; line-height: 1.05; letter-spacing: -0.03em;
          font-size: clamp(2.4rem, 6vw, 5rem);
          word-break: break-word; margin-bottom: 0.55rem;
          color: var(--text);
        }
        .ac-name-grad {
          background: linear-gradient(90deg, var(--cyan), var(--purple));
          -webkit-background-clip: text;
          -webkit-text-fill-color: transparent;
          background-clip: text;
        }

        /* ── SUB / TAGLINE ── */
        .ac-hero-sub {
          font-size: clamp(0.82rem, 1.5vw, 1.05rem);
          color: var(--muted); margin-bottom: 0.75rem; line-height: 1.6;
        }
        .ac-sub-accent { color: var(--orange); }

        .ac-hero-tagline {
          font-size: clamp(0.85rem, 1.3vw, 0.98rem);
          color: var(--muted); max-width: 480px; line-height: 1.75;
          margin-bottom: clamp(1.5rem, 3vw, 2.25rem);
        }

        /* ── BUTTONS ── */
        .ac-hero-btns { display: flex; gap: 0.75rem; flex-wrap: wrap; align-items: center; }

        .ac-btn-primary {
          background: var(--cyan); color: #000;
          padding: 11px 24px; border-radius: 99px;
          font-weight: 700; font-size: clamp(0.8rem,1.1vw,0.88rem);
          text-decoration: none; white-space: nowrap;
          display: inline-flex; align-items: center; gap: 6px;
          transition: opacity .2s, transform .15s;
        }
        .ac-btn-primary:hover { opacity: .88; transform: translateY(-2px); }

        .ac-btn-outline {
          background: transparent; color: var(--text);
          padding: 11px 24px; border-radius: 99px;
          border: 1px solid var(--border);
          font-weight: 600; font-size: clamp(0.8rem,1.1vw,0.88rem);
          text-decoration: none; white-space: nowrap;
          display: inline-flex; align-items: center; gap: 6px;
          transition: border-color .2s, color .2s;
        }
        .ac-btn-outline:hover { border-color: var(--purple); color: var(--purple); }

        /* ── STATS ── */
        .ac-stats-wrap { max-width: var(--max); width: 100%; position: relative; z-index: 1; }

        .ac-stats-bar {
          display: grid;
          /* KEY FIX: minmax(0,1fr) prevents overflow on any screen */
          grid-template-columns: repeat(4, minmax(0, 1fr));
          gap: 1px;
          margin-top: clamp(2rem, 5vw, 3.5rem);
          background: var(--border);
          border: 1px solid var(--border);
          border-radius: 14px; overflow: hidden; width: 100%;
        }
        .ac-stat-cell {
          background: var(--surface);
          padding: clamp(0.9rem,2vw,1.4rem) clamp(0.5rem,1.5vw,1rem);
          text-align: center; transition: background .2s;
          /* prevent cell from stretching past its column */
          min-width: 0;
        }
        .ac-stat-cell:hover { background: var(--surface2); }

        .ac-stat-val {
          font-size: clamp(1.15rem, 2.5vw, 2rem);
          font-weight: 800; color: var(--cyan); line-height: 1; white-space: nowrap;
        }
        .ac-stat-lbl {
          font-size: clamp(0.6rem, 0.85vw, 0.72rem);
          color: var(--muted); margin-top: 5px; font-weight: 500;
          line-height: 1.35; word-break: break-word;
        }

        /* ══════════════════════════════
           RESPONSIVE BREAKPOINTS
        ══════════════════════════════ */

        /* Tablet ≤ 1024px */
        @media (max-width: 1024px) {
          .ac-hero-name { font-size: clamp(2.4rem, 6.5vw, 4rem); }
        }

        /* Small tablet / large phone ≤ 768px */
        @media (max-width: 768px) {
          .ac-nav-links, .ac-nav-links .ac-btn-hire { display: none; }
          .ac-hamburger { display: flex; }
          .ac-hero-name { font-size: clamp(2.2rem, 8.5vw, 3.6rem); }
          /* Stats: 2 columns on tablet */
          .ac-stats-bar { grid-template-columns: repeat(2, minmax(0,1fr)); }
        }

        /* Mobile ≤ 480px */
        @media (max-width: 480px) {
          .ac-hero { min-height: auto; }
          .ac-hero-name { font-size: clamp(2rem, 10vw, 2.9rem); line-height: 1.1; }
          /* Stack buttons full-width */
          .ac-hero-btns { flex-direction: column; }
          .ac-btn-primary, .ac-btn-outline { width: 100%; justify-content: center; }
          .ac-stats-bar { grid-template-columns: repeat(2, minmax(0,1fr)); }
          .ac-stat-val { font-size: 1.35rem; }
          .ac-stat-lbl { font-size: 0.63rem; }
        }

        /* Very small phones ≤ 360px */
        @media (max-width: 360px) {
          .ac-hero-name { font-size: 1.85rem; }
          .ac-hero-sub, .ac-badge-txt { font-size: 0.72rem; }
        }

        /* Large monitors ≥ 1600px */
        @media (min-width: 1600px) {
          :root { --max: 1060px; --pad: clamp(4rem,8vw,10rem); }
          .ac-hero-name { font-size: clamp(5rem, 5.5vw, 7rem); }
          .ac-hero-sub  { font-size: 1.3rem; }
          .ac-hero-tagline { font-size: 1.15rem; max-width: 600px; }
          .ac-stat-val  { font-size: 2.5rem; }
          .ac-stat-lbl  { font-size: 0.85rem; }
        }

        /* 4K / TV ≥ 2200px */
        @media (min-width: 2200px) {
          :root { --max: 1300px; }
          .ac-hero-name { font-size: clamp(7rem, 6vw, 9rem); }
          .ac-stat-val  { font-size: 3rem; }
          .ac-badge-txt { font-size: 0.8rem; }
        }
      `}</style>

      {/* ── NAV ── */}
      <nav className="ac-nav">
        <div className="ac-logo">
          <span className="ac-logo-ac">AC</span>
          <span className="ac-logo-dev">Dev</span>
        </div>

        <ul className="ac-nav-links">
          {["About","Skills","Experience","Projects","Awards","Contact"].map(l => (
            <li key={l}><a href={`#${l.toLowerCase()}`}>{l}</a></li>
          ))}
          <li><a href="#contact" className="ac-btn-hire">Hire Me</a></li>
        </ul>

        <button className="ac-hamburger" onClick={() => setMenuOpen(o => !o)} aria-label="Toggle menu">
          <span /><span /><span />
        </button>
      </nav>

      {/* ── MOBILE MENU ── */}
      <div className={`ac-mobile-menu${menuOpen ? " open" : ""}`}>
        {["About","Skills","Experience","Projects","Awards","Contact"].map(l => (
          <a key={l} href={`#${l.toLowerCase()}`} onClick={() => setMenuOpen(false)}>{l}</a>
        ))}
        <a href="#contact" className="ac-btn-hire" style={{ alignSelf:"flex-start", marginTop:4 }}
           onClick={() => setMenuOpen(false)}>Hire Me</a>
      </div>

      {/* ── HERO ── */}
      <section className="ac-hero" id="about">
        <div className="ac-blob1" />
        <div className="ac-blob2" />

        <div className="ac-hero-inner">
          {/* Badge */}
          <div className="ac-badge">
            <span className="ac-badge-dot" />
            <span className="ac-badge-txt">Open to Opportunities</span>
          </div>

          {/* Name */}
          <h1 className="ac-hero-name">
            {name.split(" ")[0]}{" "}
            <span className="ac-name-grad">{name.split(" ")[1]}</span>
          </h1>

          {/* Subtitle */}
          <p className="ac-hero-sub">
            {title} · <span className="ac-sub-accent">{subtitle}</span>
          </p>

          {/* Tagline */}
          <p className="ac-hero-tagline">{tagline}</p>

          {/* CTAs */}
          <div className="ac-hero-btns">
            <a href={`mailto:${contact.email}`} className="ac-btn-primary">✉ Get in Touch</a>
            <a href={`https://${contact.linkedin}`} target="_blank" rel="noreferrer" className="ac-btn-outline">
              in LinkedIn
            </a>
          </div>
        </div>

        {/* Stats */}
        <div className="ac-stats-wrap">
          <div className="ac-stats-bar">
            {stats.map((s, i) => (
              <div key={i} className="ac-stat-cell">
                <div className="ac-stat-val">{s.value}</div>
                <div className="ac-stat-lbl">{s.label}</div>
              </div>
            ))}
          </div>
        </div>
      </section>
    </>
  );
}
